const env = typeof $env !== 'undefined' ? $env : {};
const supabaseUrl = (env.SUPABASE_URL || process.env.SUPABASE_URL || '').replace(/\/$/, '');
const serviceRoleKey = env.SUPABASE_SERVICE_ROLE_KEY || process.env.SUPABASE_SERVICE_ROLE_KEY || '';
const groqApiKey = env.GROQ_API_KEY || process.env.GROQ_API_KEY || '';

if (!supabaseUrl || !serviceRoleKey || !groqApiKey) {
  throw new Error('Missing SUPABASE_URL, SUPABASE_SERVICE_ROLE_KEY, or GROQ_API_KEY in n8n environment.');
}

const now = new Date();
const windowEnd = new Date(now.getTime() + 24 * 60 * 60 * 1000);
const nowIso = now.toISOString();
const windowEndIso = windowEnd.toISOString();
const runStartedAt = nowIso;

const restHeaders = {
  apikey: serviceRoleKey,
  Authorization: `Bearer ${serviceRoleKey}`,
  'Content-Type': 'application/json',
};

async function httpRequest(options) {
  return this.helpers.httpRequest({ json: true, ...options });
}

async function supabaseGet(path) {
  return httpRequest.call(this, { method: 'GET', url: `${supabaseUrl}/rest/v1/${path}`, headers: restHeaders });
}

async function supabasePost(path, body) {
  return httpRequest.call(this, {
    method: 'POST',
    url: `${supabaseUrl}/rest/v1/${path}`,
    headers: { ...restHeaders, Prefer: 'return=representation' },
    body,
  });
}

function truncateJson(value, max = 12000) {
  const raw = JSON.stringify(value || []);
  return raw.length > max ? `${raw.slice(0, max)}...` : raw;
}

function asText(value, fallback = '') {
  return typeof value === 'string' && value.trim() ? value.trim() : fallback;
}

async function findAiSessionNotification(bookingId) {
  const matches = await supabaseGet(`notifications?select=id&data->>kind=eq.ai_session_ready&data->>booking_id=eq.${bookingId}&limit=1`);
  return matches[0];
}

async function ensureCoachNotification({ booking, coachUserId, clientProfile, noteId }) {
  const existing = await findAiSessionNotification(booking.id);
  if (existing?.id) return { id: existing.id, created: false };

  const clientName = asText(clientProfile.display_name, 'your client');
  const insertedNotifications = await supabasePost('notifications', {
    user_id: coachUserId,
    type: 'booking_reminder',
    title: 'AI session briefing ready',
    body: `A pre-session briefing is ready for ${clientName}.`,
    data: {
      kind: 'ai_session_ready',
      booking_id: booking.id,
      client_id: booking.client_id,
      coach_id: booking.coach_id,
      note_id: noteId,
      scheduled_at: booking.scheduled_at,
    },
  });

  const notification = insertedNotifications[0];
  if (!notification?.id) throw new Error('Supabase did not return inserted notification id.');
  return { id: notification.id, created: true };
}

async function groqSummary(context) {
  const clientName = asText(context.clientProfile?.display_name, 'Client');
  const prompt = [
    'Create a concise pre-session briefing for a fitness coach.',
    'Use only the data provided. Do not invent injuries, diagnoses, or private facts.',
    'Write in plain text with short sections:',
    '1. Recent training',
    '2. Consistency and load',
    '3. Wins or possible PRs',
    '4. Coach attention points',
    '5. Suggested next-session focus',
    'Keep it under 220 words.',
    '',
    `Booking: ${JSON.stringify(context.booking)}`,
    `Client profile: ${JSON.stringify(context.clientProfile || {})}`,
    `Recent completed sessions: ${truncateJson(context.sessions)}`,
    `Private coach notes: ${truncateJson(context.notes)}`,
    `Recent check-ins: ${truncateJson(context.checkIns)}`,
  ].join('\n');

  const json = await httpRequest.call(this, {
    method: 'POST',
    url: 'https://api.groq.com/openai/v1/chat/completions',
    headers: {
      Authorization: `Bearer ${groqApiKey}`,
      'Content-Type': 'application/json',
    },
    body: {
      model: 'llama-3.3-70b-versatile',
      temperature: 0.25,
      messages: [
        {
          role: 'system',
          content: 'You are a careful coaching assistant. Summarize training context for a coach without medical advice or invented details.',
        },
        { role: 'user', content: prompt },
      ],
    },
  });
  const summary = asText(json.choices?.[0]?.message?.content);
  if (!summary) throw new Error(`Groq returned an empty summary for ${clientName}.`);
  return summary;
}

const bookings = await supabaseGet(
  `bookings?select=id,coach_id,client_id,scheduled_at,duration_minutes&status=eq.confirmed&scheduled_at=gte.${encodeURIComponent(nowIso)}&scheduled_at=lte.${encodeURIComponent(windowEndIso)}&order=scheduled_at.asc`
);

const results = [];
const stats = {
  run_started_at: runStartedAt,
  window_start: nowIso,
  window_end: windowEndIso,
  bookings_found: (bookings || []).length,
  generated_count: 0,
  skipped_existing_note_count: 0,
  skipped_missing_coach_user_count: 0,
  repaired_notification_count: 0,
  error_count: 0,
};

for (const booking of bookings || []) {
  try {
    const existingNotes = await supabaseGet(
      `ai_session_notes?select=id,created_at,expires_at&coach_id=eq.${booking.coach_id}&client_id=eq.${booking.client_id}&expires_at=gt.${encodeURIComponent(nowIso)}&order=created_at.desc&limit=1`
    );

    if (existingNotes.length > 0) {
      const [coachProfiles, clientProfiles] = await Promise.all([
        supabaseGet(`coach_profiles?select=id,user_id&id=eq.${booking.coach_id}&limit=1`),
        supabaseGet(`user_profiles?select=display_name&id=eq.${booking.client_id}&limit=1`),
      ]);
      const coachProfile = coachProfiles[0];
      if (!coachProfile?.user_id) {
        stats.skipped_missing_coach_user_count += 1;
        results.push({ booking_id: booking.id, status: 'skipped_missing_coach_user' });
        continue;
      }
      const notification = await ensureCoachNotification({
        booking,
        coachUserId: coachProfile.user_id,
        clientProfile: clientProfiles[0] || {},
        noteId: existingNotes[0].id,
      });
      stats.skipped_existing_note_count += 1;
      if (notification.created) stats.repaired_notification_count += 1;
      results.push({
        booking_id: booking.id,
        status: 'skipped_existing_note',
        note_id: existingNotes[0].id,
        notification_id: notification.id,
        notification_created: notification.created,
      });
      continue;
    }

    const [coachProfiles, clientProfiles, sessions, notes, checkIns] = await Promise.all([
      supabaseGet(`coach_profiles?select=id,user_id&id=eq.${booking.coach_id}&limit=1`),
      supabaseGet(`user_profiles?select=display_name,goal,activity_level,age,gender&id=eq.${booking.client_id}&limit=1`),
      supabaseGet(`workout_sessions?select=id,started_at,completed_at,duration_minutes,exercises_completed,workouts(name,difficulty)&user_id=eq.${booking.client_id}&completed_at=not.is.null&order=completed_at.desc&limit=8`),
      supabaseGet(`coach_client_notes?select=note,updated_at&coach_id=eq.${booking.coach_id}&client_id=eq.${booking.client_id}&order=updated_at.desc&limit=5`),
      supabaseGet(`check_in_responses?select=response_date,mood,energy,soreness,sleep_quality,notes,responded_at&coach_id=eq.${booking.coach_id}&client_id=eq.${booking.client_id}&order=responded_at.desc&limit=7`),
    ]);

    const coachProfile = coachProfiles[0];
    if (!coachProfile?.user_id) {
      stats.skipped_missing_coach_user_count += 1;
      results.push({ booking_id: booking.id, status: 'skipped_missing_coach_user' });
      continue;
    }

    const clientProfile = clientProfiles[0] || {};
    const summary = await groqSummary({ booking, clientProfile, sessions, notes, checkIns });

    const insertedNotes = await supabasePost('ai_session_notes', {
      coach_id: booking.coach_id,
      client_id: booking.client_id,
      summary,
      context: {
        automation: 'n8n_ai_session_prep_v1',
        booking_id: booking.id,
        scheduled_at: booking.scheduled_at,
        session_count: sessions.length,
        notes_count: notes.length,
        check_in_count: checkIns.length,
        generated_at: new Date().toISOString(),
      },
      generated_by: 'groq_n8n',
    });

    const note = insertedNotes[0];
    if (!note?.id) throw new Error('Supabase did not return inserted ai_session_notes id.');

    const notification = await ensureCoachNotification({
      booking,
      coachUserId: coachProfile.user_id,
      clientProfile,
      noteId: note.id,
    });

    stats.generated_count += 1;
    results.push({
      booking_id: booking.id,
      status: 'generated',
      note_id: note.id,
      coach_user_id: coachProfile.user_id,
      notification_id: notification.id,
      notification_created: notification.created,
    });
  } catch (error) {
    stats.error_count += 1;
    results.push({ booking_id: booking.id, status: 'error', error: error instanceof Error ? error.message : String(error) });
  }
}

const summary = {
  type: 'summary',
  status: stats.error_count > 0 ? 'completed_with_errors' : 'completed',
  finished_at: new Date().toISOString(),
  ...stats,
};

return [
  { json: summary },
  ...results.map((result) => ({ json: { type: 'booking_result', ...result } })),
];
